const views = {
  menu: el('viewMenu'),
  quiz: el('viewQuiz'),
  result: el('viewResult'),
};

const opts = {
  shuffleQuestions: el('optShuffleQuestions'),
  shuffleChoices: el('optShuffleChoices'),
  showExplanation: el('optShowExplanation'),
  autoNext: el('optAutoNext'),
};

const ui = {
  examGrid: el('examGrid'),
  btnHome: el('btnHome'),
  btnReset: el('btnReset'),
  examTitle: el('examTitle'),
  progressText: el('progressText'),
  scorePill: el('scorePill'),
  questionId: el('questionId'),
  questionText: el('questionText'),
  choicesBox: el('choicesBox'),
  feedback: el('feedback'),
  btnPrev: el('btnPrev'),
  btnSkip: el('btnSkip'),
  btnNext: el('btnNext'),
  btnFinish: el('btnFinish'),
  btnReviewWrong: el('btnReviewWrong'),
  // result
  resultScore: el('resultScore'),
  resultCorrect: el('resultCorrect'),
  resultWrong: el('resultWrong'),
  resultUnanswered: el('resultUnanswered'),
  btnRetry: el('btnRetry'),
  btnRetryWrong: el('btnRetryWrong'),
  btnBackMenu: el('btnBackMenu'),
  reviewList: el('reviewList'),
};

function showView(name){
  Object.entries(views).forEach(([k,v])=>v.classList.toggle('hidden', k!==name));
}

function shuffle(arr){
  const a = arr.slice();
  for(let i=a.length-1;i>0;i--){
    const j = Math.floor(Math.random()*(i+1));
    [a[i],a[j]]=[a[j],a[i]];
  }
  return a;
}

function storageKey(exam){
  return `fp3quiz::${exam}`;
}

function loadState(exam){
  const raw = localStorage.getItem(storageKey(exam));
  if(!raw) return null;
  try { return JSON.parse(raw); } catch(e){ return null; }
}

function saveState(exam, state){
  localStorage.setItem(storageKey(exam), JSON.stringify(state));
}

function clearState(exam){
  localStorage.removeItem(storageKey(exam));
}

function buildExamTiles(){
  ui.examGrid.innerHTML = '';
  const keys = Object.keys(QUIZ.exams).sort();
  keys.forEach(exam => {
    const tile = document.createElement('div');
    tile.className = 'exam-tile';
    tile.innerHTML = `
      <div class="name">${QUIZ.exams[exam]}</div>
      <div class="meta">全60問 / 2択・3択混在</div>
    `;
    tile.addEventListener('click', ()=>startExam(exam));
    ui.examGrid.appendChild(tile);
  });
}

let session = null;
// session = { exam, order: [index], pool: [index], currentPos, answers: {qIndex: choiceIndex|null}, mode: 'all'|'wrong' }

function initSession(exam, mode='all'){
  const base = QUIZ.data[exam];
  if(!base) throw new Error('Unknown exam '+exam);

  // Build question pool
  const indices = base.map((_,i)=>i);
  const saved = loadState(exam);

  let order = opts.shuffleQuestions.checked ? shuffle(indices) : indices.slice();

  // preserve previous order if continuing
  if(saved && saved.order && Array.isArray(saved.order) && saved.order.length===indices.length){
    order = saved.order;
  }

  // answers map
  let answers = {};
  if(saved && saved.answers) answers = saved.answers;

  // if wrong-only mode, build pool from saved answers
  let pool = order.slice();
  if(mode==='wrong'){
    pool = order.filter(i => answers[i] !== undefined && answers[i] !== null && answers[i] !== base[i].answer);
    // If no wrong answers, fallback to all
    if(pool.length===0) pool = order.slice();
  }

  let currentPos = 0;
  if(saved && typeof saved.currentPos==='number' && mode==='all') currentPos = Math.min(Math.max(saved.currentPos,0), order.length-1);

  session = { exam, order, pool, currentPos, answers, mode, showFeedback:false };
  saveState(exam, {
    order: session.order,
    answers: session.answers,
    currentPos: session.currentPos,
    updatedAt: Date.now(),
  });
}

function startExam(exam){
  initSession(exam, 'all');
  showView('quiz');
  render();
}

function currentQuestionIndex(){
  return session.pool[session.currentPos];
}

function preprocessChoices(q){
  // returns {choices:[string], correct:number, mapping:[origIndex]}
  const baseChoices = q.choices.slice();
  const mapping = baseChoices.map((_,i)=>i);
  if(!opts.shuffleChoices.checked) {
    return { choices: baseChoices, correct: q.answer, mapping };
  }
  // shuffle choices but keep mapping
  const zipped = baseChoices.map((c,i)=>({c, i}));
  const shuffled = shuffle(zipped);
  const newChoices = shuffled.map(x=>x.c);
  const newMapping = shuffled.map(x=>x.i);
  const correct = newMapping.indexOf(q.answer);
  return { choices: newChoices, correct, mapping: newMapping };
}

function scoreStats(){
  const data = QUIZ.data[session.exam];
  let correct=0, wrong=0, unanswered=0;
  for(const i of session.order){
    const a = session.answers[i];
    if(a===undefined || a===null) { unanswered++; continue; }
    if(a===data[i].answer) correct++;
    else wrong++;
  }
  return {correct, wrong, unanswered, total: session.order.length};
}

function render(){
  const data = QUIZ.data[session.exam];
  const qIndex = currentQuestionIndex();
  const q = data[qIndex];

  ui.examTitle.textContent = `【${QUIZ.exams[session.exam]}】`;
  ui.questionId.textContent = q.id;
  ui.questionText.textContent = q.question;

  const stats = scoreStats();
  ui.progressText.textContent = `進捗：${session.currentPos+1} / ${session.pool.length}（全体：${stats.correct}正解 / ${stats.total}問）`;
  ui.scorePill.textContent = `正解 ${stats.correct} / ${stats.total}`;

  // render choices
  ui.choicesBox.innerHTML = '';
  ui.feedback.classList.add('hidden');
  ui.feedback.innerHTML = '';

  const processed = preprocessChoices(q);
  // store mapping in session for this question render
  session._processed = processed;

  const selectedOrig = session.answers[qIndex];

  processed.choices.forEach((choiceText, shownIdx)=>{
    const div = document.createElement('div');
    div.className = 'choice';
    const origIdx = processed.mapping[shownIdx];
    if(selectedOrig===origIdx) div.classList.add('selected');
    div.textContent = choiceText;

    div.addEventListener('click', ()=>onSelectChoice(shownIdx));
    ui.choicesBox.appendChild(div);
  });

  // if already answered, show feedback (optional)
  if(selectedOrig !== undefined && selectedOrig !== null){
    showFeedbackForAnswered();
  }

  ui.btnPrev.disabled = session.currentPos===0;
  ui.btnNext.disabled = session.currentPos>=session.pool.length-1;
}

function showFeedbackForAnswered(){
  const data = QUIZ.data[session.exam];
  const qIndex = currentQuestionIndex();
  const q = data[qIndex];
  const processed = session._processed || preprocessChoices(q);
  const selectedOrig = session.answers[qIndex];
  if(selectedOrig===undefined || selectedOrig===null) return;

  const selectedShown = processed.mapping.indexOf(selectedOrig);
  const correctShown = processed.correct;

  // mark choices
  [...ui.choicesBox.children].forEach((node, idx)=>{
    node.classList.remove('correct','wrong');
    if(idx===correctShown) node.classList.add('correct');
    if(idx===selectedShown && selectedShown!==correctShown) node.classList.add('wrong');
  });

  if(!opts.showExplanation.checked) return;

  const ok = (selectedOrig===q.answer);
  ui.feedback.classList.remove('hidden');
  ui.feedback.innerHTML = `
    <div><span class="tag ${ok?'ok':'ng'}">${ok?'正解':'不正解'}</span>
      <span>正解：${q.choices[q.answer]}</span>
    </div>
    <div class="explain">${escapeHtml(q.explanation || '')}</div>
  `;
}

function onSelectChoice(shownIdx){
  const data = QUIZ.data[session.exam];
  const qIndex = currentQuestionIndex();
  const q = data[qIndex];
  const processed = session._processed;

  const origIdx = processed.mapping[shownIdx];
  session.answers[qIndex] = origIdx;

  saveState(session.exam, {
    order: session.order,
    answers: session.answers,
    currentPos: session.currentPos,
    updatedAt: Date.now(),
  });

  showFeedbackForAnswered();

  // auto next if enabled and correct
  if(opts.autoNext.checked && origIdx===q.answer){
    setTimeout(()=>{
      if(session.currentPos < session.pool.length-1){
        session.currentPos++;
        saveState(session.exam, {
          order: session.order,
          answers: session.answers,
          currentPos: session.currentPos,
          updatedAt: Date.now(),
        });
        render();
      }
    }, 1000);
  }
}

function move(delta){
  session.currentPos = Math.min(Math.max(session.currentPos + delta, 0), session.pool.length-1);
  saveState(session.exam, {
    order: session.order,
    answers: session.answers,
    currentPos: session.currentPos,
    updatedAt: Date.now(),
  });
  render();
}

function skip(){
  const qIndex = currentQuestionIndex();
  // mark as null explicitly to distinguish from never touched
  if(session.answers[qIndex]===undefined) session.answers[qIndex]=null;
  saveState(session.exam, {
    order: session.order,
    answers: session.answers,
    currentPos: session.currentPos,
    updatedAt: Date.now(),
  });
  if(session.currentPos < session.pool.length-1) {
    session.currentPos++;
    saveState(session.exam, {
      order: session.order,
      answers: session.answers,
      currentPos: session.currentPos,
      updatedAt: Date.now(),
    });
  }
  render();
}

function finish(){
  const stats = scoreStats();
  const pct = Math.round((stats.correct / stats.total) * 100);
  ui.resultScore.textContent = `${pct}%`;
  ui.resultCorrect.textContent = `${stats.correct}`;
  ui.resultWrong.textContent = `${stats.wrong}`;
  ui.resultUnanswered.textContent = `${stats.unanswered}`;

  buildReviewList();
  showView('result');
}

function buildReviewList(){
  const data = QUIZ.data[session.exam];
  const items = session.order.map(i=>({i, q:data[i], a: session.answers[i]}));
  ui.reviewList.innerHTML = '';

  items.forEach(({ i, q, a })=>{
    const ok = (a!==undefined && a!==null && a===q.answer);
    const status = (a===undefined || a===null) ? '未回答' : (ok?'正解':'不正解');
    const div = document.createElement('div');
    div.className = 'review-item';
    div.innerHTML = `
      <div class="head">
        <div><strong>${q.id}</strong> <span class="small">(${status})</span></div>
        <div class="small">${QUIZ.exams[session.exam]}</div>
      </div>
      <div class="qa">${escapeHtml(q.question)}</div>
      <div class="ans">
        あなた：${a===undefined || a===null ? '—' : escapeHtml(q.choices[a])}<br/>
        正解：${escapeHtml(q.choices[q.answer])}<br/>
        <span class="small">${escapeHtml(q.explanation || '')}</span>
      </div>
    `;
    ui.reviewList.appendChild(div);
  });

  // flags note (if any)
  const flags = (QUIZ.flags || []).filter(f=>f[0]===session.exam);
  if(flags.length){
    const box = document.createElement('div');
    box.className = 'review-item';
    box.innerHTML = `
      <div class="head"><div><strong>要確認メモ</strong></div><div class="small">データ点検</div></div>
      <div class="qa small">${flags.map(f=>`・${f[1]}：${f[2]}`).join('<br/>')}</div>
    `;
    ui.reviewList.prepend(box);
  }
}

function escapeHtml(s){
  return String(s)
    .replaceAll('&','&amp;')
    .replaceAll('<','&lt;')
    .replaceAll('>','&gt;')
    .replaceAll('"','&quot;')
    .replaceAll("'",'&#39;')
    .replaceAll('\n','<br/>');
}

function retry(mode){
  initSession(session.exam, mode);
  showView('quiz');
  render();
}

function goMenu(){
  showView('menu');
}

function resetCurrent(){
  if(!session || !session.exam) {
    alert('メニューから試験を選択してください。');
    return;
  }
  clearState(session.exam);
  initSession(session.exam, 'all');
  render();
}

// Wire events
ui.btnHome.addEventListener('click', ()=>goMenu());
ui.btnReset.addEventListener('click', ()=>{ if(session) resetCurrent(); else alert('まだ開始していません'); });

ui.btnPrev.addEventListener('click', ()=>move(-1));
ui.btnNext.addEventListener('click', ()=>move(+1));
ui.btnSkip.addEventListener('click', ()=>skip());
ui.btnFinish.addEventListener('click', ()=>finish());
ui.btnReviewWrong.addEventListener('click', ()=>retry('wrong'));

ui.btnRetry.addEventListener('click', ()=>retry('all'));
ui.btnRetryWrong.addEventListener('click', ()=>retry('wrong'));
ui.btnBackMenu.addEventListener('click', ()=>goMenu());

// Initial
buildExamTiles();
showView('menu');
